fn solve(nums: Vec<i64>, queries: Vec<Vec<i64>>) -> i64 {
    let mut nums = nums;
    let modulo = 1_000_000_007;

    for query in queries {
        let li = query[0] as usize;
        let ri = query[1] as usize;
        let ki = query[2] as usize;
        let vi = query[3];

        let mut idx = li;
        while idx <= ri {
            nums[idx] = (nums[idx] * vi) % modulo;
            idx += ki;
        }
    }

    nums.iter().fold(0, |acc, &x| acc ^ x)
}
